const body = $input.first().json.body;
if (!body || !body.entry) return [];

const events = [];
for (const entry of body.entry) {
  if (entry.changes) {
    for (const change of entry.changes) {
      const v = change.value;
      if (change.field === 'comments' && v.id) {
        events.push({ json: { type: 'ig_comment', comment_id: v.id, text: v.text || '', from_id: (v.from||{}).id||null, from_name: (v.from||{}).name||null } });
      }
      if (change.field === 'feed' && v.item === 'comment' && v.verb === 'add') {
        events.push({ json: { type: 'fb_comment', comment_id: v.comment_id, text: v.message || '', from_id: (v.from||{}).id||null, from_name: (v.from||{}).name||null } });
      }
    }
  }
  if (entry.messaging) {
    for (const msg of entry.messaging) {
      if (msg.message && !msg.message.is_echo) {
        const platform = body.object === 'instagram' ? 'ig_dm' : 'fb_dm';
        events.push({ json: { type: platform, sender_id: msg.sender.id, text: (msg.message.text||'').trim() } });
      }
    }
  }
}
return events;

